// Auto-generated from tarot/src/com/whim/tarot/data/TarotDeckData.java (RWS, public domain)
window.TAROT_CARDS = [{"id":0,"name":"The Fool","suit":"MAJOR","number":0,"upright":"New beginnings, spontaneity, innocence, and a leap of faith. A fresh start full of potential where you trust the journey and embrace the unknown.","reversed":"Recklessness, naivety, and foolish risk-taking. Hesitation at the cliff's edge, poor judgement, or fear that holds back a needed leap.","description":"A youth steps lightly toward a precipice, white rose and knapsack in hand, a small dog at his heels and the sun rising behind — the soul about to incarnate into experience.","image":"https://upload.wikimedia.org/wikipedia/commons/9/90/RWS_Tarot_00_Fool.jpg"},{"id":1,"name":"The Magician","suit":"MAJOR","number":1,"upright":"Manifestation, willpower, skill, and resourcefulness. You have all the tools you need to turn ideas into reality through focused intention.","reversed":"Manipulation, trickery, untapped talent, and scattered energy. Power misused or potential left idle through poor planning.","description":"A robed adept stands with one hand raised to heaven and one pointing to earth, the infinity sign above him and the four suit symbols on his table — channeling spirit into matter.","image":"https://upload.wikimedia.org/wikipedia/commons/d/de/RWS_Tarot_01_Magician.jpg"},{"id":2,"name":"The High Priestess","suit":"MAJOR","number":2,"upright":"Intuition, mystery, the subconscious, and inner wisdom. A call to trust your instincts and attend to the unseen and the unspoken.","reversed":"Secrets withheld, disconnection from intuition, and hidden agendas. Surface knowledge masking deeper truths you are ignoring.","description":"A serene priestess sits between the black and white pillars Boaz and Jachin, a crescent moon at her feet and a scroll of hidden law in her lap, veiled before the pomegranate curtain.","image":"https://upload.wikimedia.org/wikipedia/commons/8/88/RWS_Tarot_02_High_Priestess.jpg"},{"id":3,"name":"The Empress","suit":"MAJOR","number":3,"upright":"Abundance, fertility, nurturing, and creativity. A flourishing of nature, sensual pleasure, and motherly care that brings ideas and life to fruition.","reversed":"Creative block, dependence, smothering, and neglect. Stagnation or a disconnect from nurturing oneself and others.","description":"A crowned mother-figure reclines amid a wheat field and lush forest, the symbol of Venus beside her and a stream flowing nearby — the embodiment of earthly abundance.","image":"https://upload.wikimedia.org/wikipedia/commons/d/d2/RWS_Tarot_03_Empress.jpg"},{"id":4,"name":"The Emperor","suit":"MAJOR","number":4,"upright":"Authority, structure, stability, and leadership. The power of discipline, order, and a fatherly hand that builds lasting foundations.","reversed":"Tyranny, rigidity, domination, and loss of control. Authority turned overbearing, or a lack of discipline and direction.","description":"A stern ruler sits on a stone throne carved with ram's heads, holding an ankh scepter before barren mountains — worldly power founded on reason and will.","image":"https://upload.wikimedia.org/wikipedia/commons/c/c3/RWS_Tarot_04_Emperor.jpg"},{"id":5,"name":"The Hierophant","suit":"MAJOR","number":5,"upright":"Tradition, spiritual guidance, conformity, and shared belief. Learning through established institutions, mentors, and time-honored values.","reversed":"Rebellion, unconventionality, and dogma rejected. Breaking from convention or hollow ritual that no longer serves.","description":"A pope-like figure raises a hand in blessing between two pillars, two acolytes kneeling before him and crossed keys at his feet — the bridge between heaven and the faithful.","image":"https://upload.wikimedia.org/wikipedia/commons/8/8d/RWS_Tarot_05_Hierophant.jpg"},{"id":6,"name":"The Lovers","suit":"MAJOR","number":6,"upright":"Love, union, harmony, and meaningful choice. A heartfelt connection and alignment of values, or a crossroads requiring a decision of the heart.","reversed":"Disharmony, imbalance, misaligned values, and broken trust. A poor choice, temptation, or relationship friction.","description":"A man and woman stand beneath the angel Raphael, the Tree of Knowledge and the Tree of Life behind them in Eden — divine blessing upon love and conscious choice.","image":"https://upload.wikimedia.org/wikipedia/commons/d/db/RWS_Tarot_06_Lovers.jpg"},{"id":7,"name":"The Chariot","suit":"MAJOR","number":7,"upright":"Determination, willpower, victory, and control. Forward momentum achieved by reining opposing forces toward a single goal.","reversed":"Lack of direction, loss of control, and aggression. Scattered drive or being pulled apart by competing urges.","description":"An armored victor rides a chariot drawn by a black and a white sphinx, a starry canopy above and a walled city behind — mastery of opposing forces through will.","image":"https://upload.wikimedia.org/wikipedia/commons/9/9b/RWS_Tarot_07_Chariot.jpg"},{"id":8,"name":"Strength","suit":"MAJOR","number":8,"upright":"Courage, inner strength, patience, and compassion. Taming raw instinct with gentleness and a calm, confident heart.","reversed":"Self-doubt, weakness, and raw emotion unchecked. Insecurity or force used where patience was needed.","description":"A calm woman gently closes the jaws of a lion, the infinity sign above her head and a garland of flowers about her — soft power mastering the beast within.","image":"https://upload.wikimedia.org/wikipedia/commons/f/f5/RWS_Tarot_08_Strength.jpg"},{"id":9,"name":"The Hermit","suit":"MAJOR","number":9,"upright":"Introspection, solitude, soul-searching, and inner guidance. Withdrawing to seek wisdom and light your own way forward.","reversed":"Isolation, loneliness, and withdrawal. Excessive seclusion or rejecting the guidance you need.","description":"A cloaked elder stands alone on a snowy peak, lifting a lantern lit by a six-pointed star and leaning on a staff — the seeker who lights the path for others.","image":"https://upload.wikimedia.org/wikipedia/commons/4/4d/RWS_Tarot_09_Hermit.jpg"},{"id":10,"name":"Wheel of Fortune","suit":"MAJOR","number":10,"upright":"Cycles, fate, turning points, and good fortune. The wheel turns toward change and opportunity; destiny is in motion.","reversed":"Bad luck, resistance to change, and cycles broken. A downturn or clinging to control over what fate decides.","description":"A great wheel inscribed with mystic letters turns amid clouds, flanked by the sphinx, serpent, and Anubis, with the four living creatures reading at the corners — the ever-turning cycle of fortune.","image":"https://upload.wikimedia.org/wikipedia/commons/3/3c/RWS_Tarot_10_Wheel_of_Fortune.jpg"},{"id":11,"name":"Justice","suit":"MAJOR","number":11,"upright":"Fairness, truth, cause and effect, and accountability. Decisions weighed honestly; you reap what you have sown.","reversed":"Injustice, dishonesty, and lack of accountability. Unfairness, bias, or evading the consequences of one's actions.","description":"A robed judge sits between two pillars holding an upraised sword and balanced scales — impartial truth that weighs every action and renders its due.","image":"https://upload.wikimedia.org/wikipedia/commons/e/e0/RWS_Tarot_11_Justice.jpg"},{"id":12,"name":"The Hanged Man","suit":"MAJOR","number":12,"upright":"Surrender, new perspective, pause, and letting go. Suspending action to see the situation from a wholly different angle.","reversed":"Stalling, needless sacrifice, and resistance. Stagnation from refusing to release or shift your viewpoint.","description":"A man hangs serenely by one foot from a living T-cross, hands behind his back and a halo about his head — willing surrender that brings enlightenment.","image":"https://upload.wikimedia.org/wikipedia/commons/2/2b/RWS_Tarot_12_Hanged_Man.jpg"},{"id":13,"name":"Death","suit":"MAJOR","number":13,"upright":"Endings, transformation, transition, and release. The close of one chapter clearing the ground for profound renewal.","reversed":"Resistance to change, stagnation, and fear of endings. Clinging to what must pass and stalling inevitable transformation.","description":"A skeletal knight in black armor rides a white horse bearing a black banner of the white rose, as king, child, and bishop meet him and the sun rises between two towers — death as the gateway to rebirth.","image":"https://upload.wikimedia.org/wikipedia/commons/d/d7/RWS_Tarot_13_Death.jpg"},{"id":14,"name":"Temperance","suit":"MAJOR","number":14,"upright":"Balance, moderation, patience, and synthesis. Blending opposites with a calm, measured hand to find the middle path.","reversed":"Imbalance, excess, and impatience. Discord, overindulgence, or a failure to find harmony.","description":"A winged angel pours water between two cups, one foot on land and one in a stream, an iris-lined path leading to a crowned mountain — the alchemy of perfect balance.","image":"https://upload.wikimedia.org/wikipedia/commons/f/f8/RWS_Tarot_14_Temperance.jpg"},{"id":15,"name":"The Devil","suit":"MAJOR","number":15,"upright":"Bondage, addiction, materialism, and shadow. Attachments and unhealthy patterns that bind you, often by your own consent.","reversed":"Release, breaking free, and reclaiming power. Confronting fear, detaching from what enslaves you, and regaining control.","description":"A horned Baphomet looms over a chained man and woman beneath an inverted torch — the bondage of base desire, its loose chains hinting the captives could free themselves.","image":"https://upload.wikimedia.org/wikipedia/commons/5/55/RWS_Tarot_15_Devil.jpg"},{"id":16,"name":"The Tower","suit":"MAJOR","number":16,"upright":"Sudden upheaval, revelation, chaos, and awakening. A shocking collapse that tears down false structures to reveal the truth.","reversed":"Fear of change, delaying disaster, and averted catastrophe. Resisting a needed collapse or clinging to crumbling ground.","description":"Lightning strikes a tall tower and topples its crown, two figures plunging headlong into the flames below — the sudden destruction of what was built on falsehood.","image":"https://upload.wikimedia.org/wikipedia/commons/5/53/RWS_Tarot_16_Tower.jpg"},{"id":17,"name":"The Star","suit":"MAJOR","number":17,"upright":"Hope, renewal, inspiration, and serenity. Healing calm after the storm and faith that the future holds light.","reversed":"Despair, disconnection, and lost faith. Discouragement, self-doubt, or feeling cut off from hope.","description":"A nude figure kneels by a pool beneath a great star and seven smaller ones, pouring water onto land and into the water — renewal, faith, and the quiet return of hope.","image":"https://upload.wikimedia.org/wikipedia/commons/d/db/RWS_Tarot_17_Star.jpg"},{"id":18,"name":"The Moon","suit":"MAJOR","number":18,"upright":"Illusion, intuition, dreams, and the subconscious. Uncertainty where things are not as they seem; trust instinct through the fog.","reversed":"Confusion lifting, released fear, and clarity returning. Hidden truths surfacing and anxiety beginning to fade.","description":"A pale moon weeps dew over a path between two towers, a dog and a wolf baying as a crayfish crawls from the pool — the realm of dream, fear, and the deep unconscious.","image":"https://upload.wikimedia.org/wikipedia/commons/7/7f/RWS_Tarot_18_Moon.jpg"},{"id":19,"name":"The Sun","suit":"MAJOR","number":19,"upright":"Joy, success, vitality, and positivity. Warmth, clarity, and the radiant assurance that all will be well.","reversed":"Temporary gloom, blocked joy, and over-optimism. Clouded happiness or a delay in the success that is still coming.","description":"A radiant sun beams over a child riding a white horse before a wall of sunflowers, a red banner raised high — pure joy, vitality, and the triumph of light.","image":"https://upload.wikimedia.org/wikipedia/commons/1/17/RWS_Tarot_19_Sun.jpg"},{"id":20,"name":"Judgement","suit":"MAJOR","number":20,"upright":"Rebirth, reckoning, awakening, and absolution. A profound call to rise renewed, evaluate the past, and answer your higher purpose.","reversed":"Self-doubt, refusal of the call, and harsh self-judgement. Ignoring an inner summons or being trapped by past regret.","description":"An angel sounds a trumpet from the clouds as the dead rise from their coffins with arms uplifted — the great awakening and call to a higher life.","image":"https://upload.wikimedia.org/wikipedia/commons/d/dd/RWS_Tarot_20_Judgement.jpg"},{"id":21,"name":"The World","suit":"MAJOR","number":21,"upright":"Completion, fulfillment, wholeness, and accomplishment. The successful close of a great cycle and a sense of integration and triumph.","reversed":"Incompletion, loose ends, and delayed closure. A goal nearly reached but stalled by unfinished business.","description":"A dancing figure wreathed in a laurel garland holds two wands, framed by the four living creatures at the corners — the harmonious completion of the journey.","image":"https://upload.wikimedia.org/wikipedia/commons/f/ff/RWS_Tarot_21_World.jpg"},{"id":22,"name":"Ace of Wands","suit":"WANDS","number":1,"upright":"Inspiration, creative spark, new ventures, and raw potential. A surge of energy igniting a fresh project or passion.","reversed":"Delays, blocked creativity, and false starts. Lost motivation or an idea that fails to catch fire.","description":"A hand emerges from a cloud grasping a sprouting wand above a green landscape and distant castle — the seed of creative fire offered fresh.","image":"https://upload.wikimedia.org/wikipedia/commons/1/11/Wands01.jpg"},{"id":23,"name":"Two of Wands","suit":"WANDS","number":2,"upright":"Planning, foresight, personal power, and decisions. Surveying your options and charting a bold path beyond the familiar.","reversed":"Fear of the unknown, indecision, and playing it safe. Plans stalled by hesitation or a lack of vision.","description":"A robed figure holds a globe and gazes from a castle wall over land and sea, a second wand fixed beside him — the world weighed before a journey is chosen.","image":"https://upload.wikimedia.org/wikipedia/commons/0/0f/Wands02.jpg"},{"id":24,"name":"Three of Wands","suit":"WANDS","number":3,"upright":"Expansion, foresight, progress, and looking ahead. Early efforts paying off as you await ships coming in.","reversed":"Delays, obstacles, and lack of foresight. Plans frustrated or expansion stalling unexpectedly.","description":"A figure stands on a cliff watching ships sail across the sea, three wands planted around him — enterprise launched and horizons widening.","image":"https://upload.wikimedia.org/wikipedia/commons/f/ff/Wands03.jpg"},{"id":25,"name":"Four of Wands","suit":"WANDS","number":4,"upright":"Celebration, harmony, home, and joyful milestones. A happy gathering, stability, and well-earned festivity.","reversed":"Tension at home, transition, and lack of harmony. Postponed celebration or instability beneath the surface.","description":"A garlanded canopy stands on four wands as two figures raise bouquets before a festive castle — homecoming and shared rejoicing.","image":"https://upload.wikimedia.org/wikipedia/commons/a/a4/Wands04.jpg"},{"id":26,"name":"Five of Wands","suit":"WANDS","number":5,"upright":"Conflict, competition, rivalry, and tension. A scramble of clashing wills, disagreements, or spirited contest.","reversed":"Avoiding conflict, resolution, and inner tension. Quarrels ending or strife suppressed rather than settled.","description":"Five youths brandish wands in a chaotic mock-battle, each striking a different angle — the friction of competing energies.","image":"https://upload.wikimedia.org/wikipedia/commons/9/9d/Wands05.jpg"},{"id":27,"name":"Six of Wands","suit":"WANDS","number":6,"upright":"Victory, public recognition, success, and confidence. Triumph acknowledged and well-deserved acclaim.","reversed":"Egotism, fall from grace, and lack of recognition. Private doubt, delayed reward, or pride before a stumble.","description":"A laurel-crowned rider parades on a white horse amid a cheering crowd, a victory wreath on his wand — public acclaim for a hard-won win.","image":"https://upload.wikimedia.org/wikipedia/commons/3/3b/Wands06.jpg"},{"id":28,"name":"Seven of Wands","suit":"WANDS","number":7,"upright":"Defiance, perseverance, standing your ground, and courage. Holding the high position against challengers.","reversed":"Overwhelm, giving up, and yielding ground. Exhaustion from defending or a position abandoned under pressure.","description":"A man on higher ground wields his wand against six rising from below — the defense of conviction against many challengers.","image":"https://upload.wikimedia.org/wikipedia/commons/e/e4/Wands07.jpg"},{"id":29,"name":"Eight of Wands","suit":"WANDS","number":8,"upright":"Swift movement, momentum, news, and rapid progress. Events accelerating and messages arriving fast.","reversed":"Delays, frustration, and scattered energy. Stalled momentum or haste that misfires.","description":"Eight wands fly in parallel through open sky over a green valley and river — swift action speeding to its target.","image":"https://upload.wikimedia.org/wikipedia/commons/6/6b/Wands08.jpg"},{"id":30,"name":"Nine of Wands","suit":"WANDS","number":9,"upright":"Resilience, persistence, last stand, and boundaries. Battle-worn but unbroken, guarding what you have gained.","reversed":"Exhaustion, paranoia, and defensiveness. Wearing down, distrust, or refusing to lower the guard.","description":"A bandaged figure leans warily on his wand before a fence of eight others — weary vigilance before the final push.","image":"https://upload.wikimedia.org/wikipedia/commons/e/e7/Wands09.jpg"},{"id":31,"name":"Ten of Wands","suit":"WANDS","number":10,"upright":"Burden, responsibility, hard work, and overload. Carrying a heavy load near the goal, perhaps too much alone.","reversed":"Release, delegation, and collapse under strain. Setting down burdens or buckling beneath them.","description":"A man struggles forward bearing all ten wands in his arms toward a distant town — the weight of obligations carried to the end.","image":"https://upload.wikimedia.org/wikipedia/commons/0/0b/Wands10.jpg"},{"id":32,"name":"Page of Wands","suit":"WANDS","number":11,"upright":"Enthusiasm, exploration, free spirit, and discovery. An eager messenger of new ideas and adventurous beginnings.","reversed":"Hesitation, restlessness, and immature haste. Scattered enthusiasm or news delayed.","description":"A youth in a salamander-patterned tunic regards his flowering wand amid desert dunes — curiosity ablaze with possibility.","image":"https://upload.wikimedia.org/wikipedia/commons/6/6a/Wands11.jpg"},{"id":33,"name":"Knight of Wands","suit":"WANDS","number":12,"upright":"Action, adventure, passion, and impulsiveness. Charging boldly toward a goal with fiery energy.","reversed":"Recklessness, haste, and frustration. Impatience, anger, or a venture that fizzles for lack of follow-through.","description":"An armored knight on a rearing horse charges forward, wand in hand, salamanders on his tunic — passionate momentum in full gallop.","image":"https://upload.wikimedia.org/wikipedia/commons/1/16/Wands12.jpg"},{"id":34,"name":"Queen of Wands","suit":"WANDS","number":13,"upright":"Confidence, warmth, courage, and vivacity. A magnetic, determined spirit who inspires and leads with charisma.","reversed":"Jealousy, insecurity, and demanding moods. Self-doubt or fiery temperament turned inward.","description":"A crowned queen sits with a sunflower and her wand, a black cat at her feet — radiant confidence and warm-hearted authority.","image":"https://upload.wikimedia.org/wikipedia/commons/0/0d/Wands13.jpg"},{"id":35,"name":"King of Wands","suit":"WANDS","number":14,"upright":"Leadership, vision, boldness, and entrepreneurship. A natural-born leader who turns inspired vision into bold action.","reversed":"Impulsiveness, domineering, and overbearing pride. Vision without patience or leadership turned ruthless.","description":"A robed king holds a flowering wand on a throne adorned with lions and salamanders — visionary command and mature creative fire.","image":"https://upload.wikimedia.org/wikipedia/commons/c/ce/Wands14.jpg"},{"id":36,"name":"Ace of Cups","suit":"CUPS","number":1,"upright":"New love, emotional awakening, compassion, and overflowing feeling. The heart opening to joy, intuition, and connection.","reversed":"Blocked emotions, emptiness, and repressed feelings. Love withheld or a heart closed off.","description":"A hand from a cloud offers a chalice overflowing with five streams as a dove descends with the host — the wellspring of love and spirit.","image":"https://upload.wikimedia.org/wikipedia/commons/3/36/Cups01.jpg"},{"id":37,"name":"Two of Cups","suit":"CUPS","number":2,"upright":"Partnership, mutual attraction, union, and connection. A balanced bond of love, friendship, or harmony between two.","reversed":"Imbalance, breakup, and disharmony. Tension, miscommunication, or a fractured connection.","description":"A man and woman pledge their cups beneath the caduceus and winged lion's head — the sacred union of two hearts.","image":"https://upload.wikimedia.org/wikipedia/commons/f/f8/Cups02.jpg"},{"id":38,"name":"Three of Cups","suit":"CUPS","number":3,"upright":"Friendship, celebration, community, and joy. Coming together to rejoice with friends and shared good fortune.","reversed":"Overindulgence, gossip, and isolation. Excess, frayed friendships, or a third party intruding.","description":"Three women raise their cups in a joyful dance amid a bountiful harvest — fellowship and celebration.","image":"https://upload.wikimedia.org/wikipedia/commons/7/7a/Cups03.jpg"},{"id":39,"name":"Four of Cups","suit":"CUPS","number":4,"upright":"Apathy, contemplation, discontent, and withdrawal. Disengaged and brooding, overlooking what is offered.","reversed":"New awareness, acceptance, and re-engagement. Boredom lifting and renewed openness to opportunity.","description":"A youth sits beneath a tree with arms crossed, ignoring a cup offered by a cloud-borne hand — discontent blind to fresh offerings.","image":"https://upload.wikimedia.org/wikipedia/commons/3/35/Cups04.jpg"},{"id":40,"name":"Five of Cups","suit":"CUPS","number":5,"upright":"Loss, grief, regret, and disappointment. Mourning what spilled while two cups still stand behind you.","reversed":"Acceptance, recovery, and moving on. Healing from loss and turning toward what remains.","description":"A cloaked figure grieves over three spilled cups, two upright behind him, a bridge to a castle beyond the river — sorrow that overlooks remaining hope.","image":"https://upload.wikimedia.org/wikipedia/commons/d/d7/Cups05.jpg"},{"id":41,"name":"Six of Cups","suit":"CUPS","number":6,"upright":"Nostalgia, innocence, memories, and reunion. The sweetness of the past, childhood joy, and kindness shared.","reversed":"Clinging to the past, stuck in memory, and naivety. Living in nostalgia or refusing to grow up.","description":"A child offers a flower-filled cup to another in a sunlit courtyard — the warmth of memory and innocent generosity.","image":"https://upload.wikimedia.org/wikipedia/commons/1/17/Cups06.jpg"},{"id":42,"name":"Seven of Cups","suit":"CUPS","number":7,"upright":"Choices, fantasy, illusion, and wishful thinking. A dazzle of options where not all is as it appears.","reversed":"Clarity, decisiveness, and disillusion. Cutting through fantasy to choose with focus.","description":"A figure faces seven cups floating in cloud, each bearing a different vision — jewels, a wreath, a dragon, a shrouded figure — the temptations of imagination.","image":"https://upload.wikimedia.org/wikipedia/commons/a/ae/Cups07.jpg"},{"id":43,"name":"Eight of Cups","suit":"CUPS","number":8,"upright":"Walking away, withdrawal, seeking deeper meaning, and abandonment. Leaving behind what no longer fulfills to search for more.","reversed":"Fear of moving on, aimlessness, and stagnation. Clinging to an empty situation or drifting without purpose.","description":"A cloaked traveler turns away from eight stacked cups, journeying toward mountains under an eclipsed moon — the brave departure toward something deeper.","image":"https://upload.wikimedia.org/wikipedia/commons/6/60/Cups08.jpg"},{"id":44,"name":"Nine of Cups","suit":"CUPS","number":9,"upright":"Contentment, satisfaction, wishes fulfilled, and emotional well-being. The 'wish card' of comfort and gratitude.","reversed":"Smugness, overindulgence, and unfulfilled wishes. Complacency or seeking happiness in excess.","description":"A satisfied man sits with arms folded before an arc of nine cups — emotional fulfillment and the granting of a wish.","image":"https://upload.wikimedia.org/wikipedia/commons/2/24/Cups09.jpg"},{"id":45,"name":"Ten of Cups","suit":"CUPS","number":10,"upright":"Harmony, happy family, lasting joy, and emotional fulfillment. The bliss of love, home, and togetherness.","reversed":"Broken home, disconnection, and misaligned values. Domestic discord or a picture-perfect ideal unmet.","description":"A couple raises their arms toward a rainbow of ten cups as two children dance, a cottage by the river beyond — the fullness of shared happiness.","image":"https://upload.wikimedia.org/wikipedia/commons/8/84/Cups10.jpg"},{"id":46,"name":"Page of Cups","suit":"CUPS","number":11,"upright":"Creative inspiration, intuition, sensitivity, and gentle messages. A dreamy messenger of new feelings and imaginative ideas.","reversed":"Emotional immaturity, escapism, and creative block. Moodiness or feelings ignored.","description":"A young page in a flowered tunic regards a fish surfacing from his cup beside a wavy sea — imagination and tender intuition awakening.","image":"https://upload.wikimedia.org/wikipedia/commons/a/ad/Cups11.jpg"},{"id":47,"name":"Knight of Cups","suit":"CUPS","number":12,"upright":"Romance, charm, idealism, and following the heart. A poetic messenger pursuing love and beauty.","reversed":"Moodiness, unrealistic ideals, and disappointment. Charm masking inconsistency or fantasy over substance.","description":"A gentle knight rides slowly bearing a cup, winged helm and heels, a river winding to the hills — the romantic in pursuit of his ideal.","image":"https://upload.wikimedia.org/wikipedia/commons/f/fa/Cups12.jpg"},{"id":48,"name":"Queen of Cups","suit":"CUPS","number":13,"upright":"Compassion, emotional depth, intuition, and nurturing. A loving, empathic soul attuned to feeling and care.","reversed":"Emotional insecurity, overwhelm, and dependence. Feelings turned overwhelming or boundaries lost.","description":"A queen gazes into an ornate lidded cup upon a throne at the water's edge — deep empathy and the wisdom of the heart.","image":"https://upload.wikimedia.org/wikipedia/commons/6/62/Cups13.jpg"},{"id":49,"name":"King of Cups","suit":"CUPS","number":14,"upright":"Emotional balance, compassion, diplomacy, and calm control. Mastery of feeling — steady, wise, and caring under pressure.","reversed":"Emotional manipulation, moodiness, and volatility. Feelings repressed or used to control others.","description":"A king sits enthroned on a turbulent sea holding a cup and scepter, calm amid the waves — emotional mastery steady within the storm.","image":"https://upload.wikimedia.org/wikipedia/commons/0/04/Cups14.jpg"},{"id":50,"name":"Ace of Swords","suit":"SWORDS","number":1,"upright":"Clarity, breakthrough, truth, and mental power. A sharp new insight cutting through confusion to reveal the truth.","reversed":"Confusion, miscommunication, and misused force. Clouded thinking or a breakthrough turned destructive.","description":"A hand from a cloud grips an upright sword crowned with laurel above stark peaks — the triumph of clear thought and decisive truth.","image":"https://upload.wikimedia.org/wikipedia/commons/1/1a/Swords01.jpg"},{"id":51,"name":"Two of Swords","suit":"SWORDS","number":2,"upright":"Difficult choices, stalemate, indecision, and avoidance. A tense impasse where you refuse to see the way forward.","reversed":"Indecision resolved, information revealed, and release. The blindfold lifting and a choice finally made.","description":"A blindfolded woman holds two crossed swords before a moonlit sea — a guarded heart at an uneasy stalemate.","image":"https://upload.wikimedia.org/wikipedia/commons/9/9e/Swords02.jpg"},{"id":52,"name":"Three of Swords","suit":"SWORDS","number":3,"upright":"Heartbreak, sorrow, painful truth, and grief. Emotional pain, betrayal, or loss that pierces the heart.","reversed":"Recovery, forgiveness, and releasing pain. Healing after heartbreak and the easing of grief.","description":"Three swords pierce a red heart against a stormy, rain-swept sky — sorrow and the sharp clarity of painful truth.","image":"https://upload.wikimedia.org/wikipedia/commons/0/02/Swords03.jpg"},{"id":53,"name":"Four of Swords","suit":"SWORDS","number":4,"upright":"Rest, recovery, contemplation, and respite. A needed pause to heal and restore before re-engaging.","reversed":"Restlessness, burnout, and stagnation. Pushing on without rest or avoiding necessary recovery.","description":"A knight lies in repose atop a tomb, three swords on the wall and one beneath him, hands in prayer — stillness and recuperation.","image":"https://upload.wikimedia.org/wikipedia/commons/b/bf/Swords04.jpg"},{"id":54,"name":"Five of Swords","suit":"SWORDS","number":5,"upright":"Conflict, defeat, hollow victory, and discord. Winning at a cost, or loss amid tension and ill will.","reversed":"Reconciliation, making amends, and releasing resentment. Moving past conflict toward repair.","description":"A smirking man gathers swords as two defeated figures walk away beneath a ragged sky — a victory that leaves only emptiness.","image":"https://upload.wikimedia.org/wikipedia/commons/2/23/Swords05.jpg"},{"id":55,"name":"Six of Swords","suit":"SWORDS","number":6,"upright":"Transition, moving on, recovery, and safe passage. Leaving troubled waters for calmer shores.","reversed":"Stuck, resistance to change, and unfinished business. Unable to move on or carrying baggage along.","description":"A ferryman poles a boat bearing a cloaked woman and child across still water toward a far shore, six swords upright in the hull — passage from turmoil to calm.","image":"https://upload.wikimedia.org/wikipedia/commons/2/29/Swords06.jpg"},{"id":56,"name":"Seven of Swords","suit":"SWORDS","number":7,"upright":"Deception, strategy, stealth, and getting away. Acting alone or by cunning, sometimes dishonestly.","reversed":"Confession, conscience, and coming clean. Deception exposed or a change of heart.","description":"A man tiptoes from a camp carrying five swords with a sly backward glance, two left behind — cunning, secrecy, and the lone gambit.","image":"https://upload.wikimedia.org/wikipedia/commons/3/34/Swords07.jpg"},{"id":57,"name":"Eight of Swords","suit":"SWORDS","number":8,"upright":"Restriction, feeling trapped, self-limiting beliefs, and powerlessness. A prison largely of the mind's own making.","reversed":"Self-acceptance, freedom, and new perspective. Releasing the bonds and stepping into your own power.","description":"A bound, blindfolded woman stands hemmed by eight swords before a distant castle — restriction that the mind could yet escape.","image":"https://upload.wikimedia.org/wikipedia/commons/a/a7/Swords08.jpg"},{"id":58,"name":"Nine of Swords","suit":"SWORDS","number":9,"upright":"Anxiety, worry, fear, and sleepless nights. The torment of the mind in the darkness, often worse than reality.","reversed":"Hope returning, releasing worry, and recovery. Anxiety easing as fears are faced in the light.","description":"A figure sits up in bed, face in hands, nine swords mounted on the wall behind — the anguish of fear and midnight dread.","image":"https://upload.wikimedia.org/wikipedia/commons/2/2f/Swords09.jpg"},{"id":59,"name":"Ten of Swords","suit":"SWORDS","number":10,"upright":"Painful ending, rock bottom, betrayal, and collapse. The worst has happened, but with it comes finality and dawn.","reversed":"Recovery, regeneration, and the worst behind you. Slowly rising from a painful end toward renewal.","description":"A fallen figure lies pierced by ten swords along the shore as a golden dawn breaks on the horizon — a definitive ending and the promise of a new day.","image":"https://upload.wikimedia.org/wikipedia/commons/d/d4/Swords10.jpg"},{"id":60,"name":"Page of Swords","suit":"SWORDS","number":11,"upright":"Curiosity, vigilance, new ideas, and mental energy. A keen, restless mind hungry for truth and quick to act.","reversed":"Deception, haste, and scattered thoughts. Gossip, recklessness, or cutting words.","description":"A youth stands on a windswept ridge brandishing a sword aloft, hair and clouds streaming — alert, inquisitive intellect.","image":"https://upload.wikimedia.org/wikipedia/commons/4/4c/Swords11.jpg"},{"id":61,"name":"Knight of Swords","suit":"SWORDS","number":12,"upright":"Ambition, drive, decisive action, and bold ideas. Charging headlong toward a goal with relentless focus.","reversed":"Recklessness, impatience, and aggression. Rushing in without thought or trampling others in haste.","description":"An armored knight charges full tilt on a galloping horse, sword raised against a wild sky — the rush of focused, headstrong intellect.","image":"https://upload.wikimedia.org/wikipedia/commons/b/b0/Swords12.jpg"},{"id":62,"name":"Queen of Swords","suit":"SWORDS","number":13,"upright":"Clear thinking, independence, honesty, and perception. A sharp, fair mind that sees through illusion and speaks the truth.","reversed":"Coldness, bitterness, and harsh judgement. Detachment turned cruel or cutting criticism.","description":"A queen sits enthroned above the clouds, sword upright and one hand outstretched — incisive clarity tempered by experience.","image":"https://upload.wikimedia.org/wikipedia/commons/d/d4/Swords13.jpg"},{"id":63,"name":"King of Swords","suit":"SWORDS","number":14,"upright":"Authority, intellect, truth, and ethical judgement. Clear, principled leadership guided by reason and fairness.","reversed":"Tyranny, manipulation, and cold rationality. Intellect used to dominate or judgement without compassion.","description":"A king sits frontally enthroned holding an upright sword, butterflies and crescent on his throne — disciplined intellect and impartial authority.","image":"https://upload.wikimedia.org/wikipedia/commons/3/33/Swords14.jpg"},{"id":64,"name":"Ace of Pentacles","suit":"PENTACLES","number":1,"upright":"New opportunity, prosperity, abundance, and manifestation. A tangible new beginning in money, work, or material security.","reversed":"Lost opportunity, scarcity, and poor planning. A promising venture squandered or material insecurity.","description":"A hand from a cloud presents a golden pentacle above a flowering garden with an archway to distant mountains — a seed of prosperity offered.","image":"https://upload.wikimedia.org/wikipedia/commons/f/fd/Pents01.jpg"},{"id":65,"name":"Two of Pentacles","suit":"PENTACLES","number":2,"upright":"Balance, adaptability, juggling priorities, and time management. Keeping multiple demands in graceful motion.","reversed":"Overwhelm, disorganization, and dropped balls. Too many commitments and losing the juggle.","description":"A young man dances while juggling two pentacles bound by an infinity loop as ships ride the waves behind — adaptable balance amid life's ups and downs.","image":"https://upload.wikimedia.org/wikipedia/commons/9/9f/Pents02.jpg"},{"id":66,"name":"Three of Pentacles","suit":"PENTACLES","number":3,"upright":"Teamwork, collaboration, skill, and craftsmanship. Building something of quality through cooperation and expertise.","reversed":"Disharmony, poor teamwork, and mediocrity. Misaligned effort or skills going unrecognized.","description":"A craftsman is consulted by a monk and a noble as he works in a cathedral — the union of skill, planning, and collaboration.","image":"https://upload.wikimedia.org/wikipedia/commons/4/42/Pents03.jpg"},{"id":67,"name":"Four of Pentacles","suit":"PENTACLES","number":4,"upright":"Security, control, saving, and holding on. Guarding resources tightly, sometimes to the point of possessiveness.","reversed":"Greed loosening, generosity, and letting go. Releasing a grip on wealth or, conversely, financial instability.","description":"A crowned figure clutches one pentacle to his chest, stands on two, and balances one on his head before a city — security held in a fearful grip.","image":"https://upload.wikimedia.org/wikipedia/commons/3/35/Pents04.jpg"},{"id":68,"name":"Five of Pentacles","suit":"PENTACLES","number":5,"upright":"Hardship, loss, insecurity, and isolation. Material or spiritual lack and the feeling of being left out in the cold.","reversed":"Recovery, renewed hope, and help arriving. Coming through hard times and finding support.","description":"Two destitute figures trudge through snow past a lit stained-glass window — poverty and the warmth that waits just out of reach.","image":"https://upload.wikimedia.org/wikipedia/commons/9/96/Pents05.jpg"},{"id":69,"name":"Six of Pentacles","suit":"PENTACLES","number":6,"upright":"Generosity, giving and receiving, charity, and balance. The fair flow of resources between those who have and have not.","reversed":"Strings attached, inequality, and debt. Imbalanced giving, dependency, or charity that controls.","description":"A merchant weighs coins on a scale while dispensing alms to two kneeling beggars — the balanced exchange of giving and receiving.","image":"https://upload.wikimedia.org/wikipedia/commons/a/a6/Pents06.jpg"},{"id":70,"name":"Seven of Pentacles","suit":"PENTACLES","number":7,"upright":"Patience, investment, perseverance, and long-term view. Pausing to assess the slow growth of your efforts.","reversed":"Impatience, poor return, and wasted effort. Frustration at slow progress or a failing investment.","description":"A farmer leans on his hoe regarding seven pentacles ripening on a leafy vine — patient labor awaiting its harvest.","image":"https://upload.wikimedia.org/wikipedia/commons/6/6a/Pents07.jpg"},{"id":71,"name":"Eight of Pentacles","suit":"PENTACLES","number":8,"upright":"Diligence, skill development, mastery, and dedication. Focused, repeated effort that hones true craftsmanship.","reversed":"Perfectionism, uninspired work, and shortcuts. Tedium, sloppiness, or skill misapplied.","description":"An apprentice carves pentacle after pentacle at his bench, finished coins displayed beside him — devoted practice toward mastery.","image":"https://upload.wikimedia.org/wikipedia/commons/4/49/Pents08.jpg"},{"id":72,"name":"Nine of Pentacles","suit":"PENTACLES","number":9,"upright":"Abundance, self-sufficiency, luxury, and reward. Enjoying the fruits of independent effort in comfort and grace.","reversed":"Over-dependence, financial setback, and hollow luxury. Self-worth tied to wealth or comfort threatened.","description":"An elegant woman stands in a lush vineyard with a hooded falcon on her gloved hand — refined self-made abundance.","image":"https://upload.wikimedia.org/wikipedia/commons/f/f0/Pents09.jpg"},{"id":73,"name":"Ten of Pentacles","suit":"PENTACLES","number":10,"upright":"Wealth, legacy, family, and lasting security. Enduring prosperity, inheritance, and the stability of established foundations.","reversed":"Financial loss, family disputes, and instability. Legacy threatened or fleeting material gain.","description":"An elder with hounds watches three generations beneath an archway hung with ten pentacles — established wealth and lasting legacy.","image":"https://upload.wikimedia.org/wikipedia/commons/4/42/Pents10.jpg"},{"id":74,"name":"Page of Pentacles","suit":"PENTACLES","number":11,"upright":"Ambition, study, new opportunity, and diligence. A grounded learner planting seeds for future prosperity.","reversed":"Procrastination, lack of progress, and missed chances. Ideas left unrealized or studies neglected.","description":"A youth gazes intently at a pentacle held aloft in a green, flowering field — the student of tangible ambitions.","image":"https://upload.wikimedia.org/wikipedia/commons/e/ec/Pents11.jpg"},{"id":75,"name":"Knight of Pentacles","suit":"PENTACLES","number":12,"upright":"Reliability, hard work, routine, and responsibility. Steady, methodical effort that sees commitments through.","reversed":"Stagnation, boredom, and stubbornness. Routine turned to rut or progress stalled by inertia.","description":"An armored knight sits motionless on a sturdy horse, holding a pentacle above plowed fields — patient, dependable diligence.","image":"https://upload.wikimedia.org/wikipedia/commons/d/d5/Pents12.jpg"},{"id":76,"name":"Queen of Pentacles","suit":"PENTACLES","number":13,"upright":"Nurturing, practicality, abundance, and security. A warm, capable provider who tends home, work, and others with grounded care.","reversed":"Self-neglect, smothering, and work-life imbalance. Care withheld from oneself or material worries overwhelming.","description":"A queen cradles a pentacle on a throne carved with fruit and goats, a rabbit by her feet in a verdant bower — bountiful, down-to-earth care.","image":"https://upload.wikimedia.org/wikipedia/commons/8/88/Pents13.jpg"},{"id":77,"name":"King of Pentacles","suit":"PENTACLES","number":14,"upright":"Prosperity, leadership, security, and discipline. A successful, grounded provider who has mastered the material world.","reversed":"Greed, materialism, and stubborn control. Wealth hoarded or success turned to corruption.","description":"A robed king sits amid grapevines, scepter and pentacle in hand, a castle and bull carvings about him — abundant, stable mastery of the material realm.","image":"https://upload.wikimedia.org/wikipedia/commons/1/1c/Pents14.jpg"}];
